import React, { useState } from 'react';
import { Link } from 'react-router-dom';

const VerifyCertificate = () => {
  const [certificateId, setCertificateId] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  
  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!certificateId.trim()) {
      return;
    }
    
    setLoading(true);
    
    // 模拟API调用
    setTimeout(() => {
      // 在实际应用中，这里应该是一个API调用
      const isValid = Math.random() > 0.3; // 70% 概率返回有效
      
      if (isValid) {
        setResult({
          valid: true,
          data: {
            id: certificateId,
            recipientName: "John Doe",
            program: "Bachelor of Computer Science",
            issueDate: "2023-08-15",
            issuer: "Global Horizon University"
          }
        });
      } else {
        setResult({
          valid: false,
          message: "Certificate not found or has been revoked. Please check the ID and try again."
        });
      }
      
      setLoading(false);
    }, 1500);
  };
  
  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md mx-auto">
        <div className="text-center mb-8">
          <h2 className="text-3xl font-extrabold text-gray-900">
            Verify Certificate
          </h2>
          <p className="mt-2 text-sm text-gray-600">
            Enter the certificate ID to verify its authenticity
          </p>
          <div className="mt-2">
            <Link to="/certificates" className="text-sm font-medium text-blue-600 hover:text-blue-500">
              ← Back to Certificate Wall
            </Link>
          </div>
        </div>
        
        <div className="bg-white py-8 px-4 shadow sm:rounded-lg sm:px-10">
          <form className="space-y-6" onSubmit={handleSubmit}>
            <div>
              <label htmlFor="certificate-id" className="block text-sm font-medium text-gray-700">
                Certificate ID
              </label>
              <div className="mt-1">
                <input
                  id="certificate-id"
                  name="certificate-id"
                  type="text"
                  required
                  value={certificateId}
                  onChange={(e) => setCertificateId(e.target.value)}
                  className="appearance-none block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm placeholder-gray-400 focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm"
                  placeholder="e.g. GHU-2023-123456"
                />
              </div>
              <p className="mt-2 text-xs text-gray-500">
                The certificate ID is located on the bottom of your certificate document
              </p>
            </div>
            
            <div>
              <button
                type="submit"
                disabled={loading}
                className="w-full flex justify-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:opacity-50"
              >
                {loading ? (
                  <span className="flex items-center">
                    <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Verifying...
                  </span>
                ) : (
                  "Verify Certificate"
                )}
              </button>
            </div>
          </form>
          
          {result && (
            <div className="mt-8">
              {result.valid ? (
                <div className="rounded-md bg-green-50 p-4 border border-green-200">
                  <div className="flex">
                    <div className="flex-shrink-0">
                      <svg className="h-5 w-5 text-green-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                      </svg>
                    </div>
                    <div className="ml-3">
                      <h3 className="text-sm font-medium text-green-800">Valid Certificate</h3>
                      <div className="mt-4 text-sm text-green-700">
                        <div className="grid grid-cols-3 gap-4">
                          <div className="col-span-1 font-semibold">ID:</div>
                          <div className="col-span-2">{result.data.id}</div>
                          
                          <div className="col-span-1 font-semibold">Name:</div>
                          <div className="col-span-2">{result.data.recipientName}</div>
                          
                          <div className="col-span-1 font-semibold">Program:</div>
                          <div className="col-span-2">{result.data.program}</div>
                          
                          <div className="col-span-1 font-semibold">Issue Date:</div>
                          <div className="col-span-2">{result.data.issueDate}</div>
                          
                          <div className="col-span-1 font-semibold">Issuer:</div>
                          <div className="col-span-2">{result.data.issuer}</div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="rounded-md bg-red-50 p-4 border border-red-200">
                  <div className="flex">
                    <div className="flex-shrink-0">
                      <svg className="h-5 w-5 text-red-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                      </svg>
                    </div>
                    <div className="ml-3">
                      <h3 className="text-sm font-medium text-red-800">Invalid Certificate</h3>
                      <div className="mt-2 text-sm text-red-700">
                        <p>{result.message}</p>
                      </div>
                    </div>
                  </div>
                </div>
              )}
              
              <div className="mt-6 flex justify-center">
                <Link
                  to="/certificates"
                  className="inline-flex items-center px-4 py-2 border border-gray-300 shadow-sm text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                >
                  Return to Certificate Wall
                </Link>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default VerifyCertificate;
